// Package cli — shared helpers for `forge map` (and formerly `forge audit`,
// which moved to the internal/cli/audit group). These walk the project tree
// to classify migrations and forge-generated files. They stay in package cli
// because map.go consumes them directly; the audit group keeps its own copy
// of isForgeGeneratedBanner (it's a five-line stdlib wrapper, duplicated per
// cmdutil's policy rather than shared through a leaf package).
package cli

import (
	"io/fs"
	"os"
	"path/filepath"
	"regexp"
	"strings"
)

// createTableRE naïvely matches "CREATE TABLE [IF NOT EXISTS] <name>". It's a
// rough heuristic — the authoritative answer would parse SQL — but it captures
// the 95% case and the 5% it misses tend to be exotic forms (DDL inside CTE,
// etc.) that would never appear in a forge-generated migration.
var createTableRE = regexp.MustCompile(`(?i)CREATE\s+TABLE(?:\s+IF\s+NOT\s+EXISTS)?\s+["` + "`" + `]?([a-zA-Z_][a-zA-Z0-9_]*)["` + "`" + `]?`)

// tablesFromMigrations greps CREATE TABLE statements out of every .sql under
// dir (skipping .down. migrations, which DROP rather than CREATE).
func tablesFromMigrations(dir string) map[string]struct{} {
	out := map[string]struct{}{}
	_ = filepath.WalkDir(dir, func(path string, d fs.DirEntry, err error) error {
		if err != nil || d.IsDir() {
			return nil
		}
		if !strings.HasSuffix(path, ".sql") {
			return nil
		}
		// Skip "down" migrations — they DROP TABLE, not CREATE.
		if strings.Contains(filepath.Base(path), ".down.") {
			return nil
		}
		data, err := os.ReadFile(path)
		if err != nil {
			return nil
		}
		for _, m := range createTableRE.FindAllStringSubmatch(string(data), -1) {
			if len(m) > 1 {
				out[strings.ToLower(m[1])] = struct{}{}
			}
		}
		return nil
	})
	return out
}

// isForgeGeneratedBanner returns true when the file's first line declares it
// as "Code generated by forge" — the legacy authorship marker from before
// embedded forge:hash certification.
func isForgeGeneratedBanner(path string) bool {
	f, err := os.Open(path)
	if err != nil {
		return false
	}
	defer func() { _ = f.Close() }()
	buf := make([]byte, 256)
	n, _ := f.Read(buf)
	head := string(buf[:n])
	if i := strings.IndexByte(head, '\n'); i >= 0 {
		head = head[:i]
	}
	return strings.Contains(head, "Code generated by forge")
}
